/* =========================================================
   결과 조회 함수
   answers[0] = 나이 선택 인덱스 (0=10대, 1=20대, ...)
   typeCode   = 'TYPE_1' 등
   ========================================================= */
function getResult(typeCode, ageIdx) {
  const ageKey = AGE_KEYS[ageIdx] || '20s';
  const typeData = RESULTS[typeCode];
  if (!typeData) return RESULTS['TYPE_6']['20s']; // 폴백
  return typeData[ageKey] || typeData['20s'] || RESULTS['TYPE_6']['20s'];
}
